urlset:

    {{ base_url }}


    {{ base_url }}event/list/


    {{ base_url }}community/list/


    {{ base_url }}about/


    {{ base_url }}event/detail/history/


{% for event_detail in event_details %}

        {{ base_url }}event/detail/{{ event_detail.pk }}/
        {{ event_detail.updated_at|date:"Y-m-d" }}

{% endfor %}
{% for community in communities %}

        {{ base_url }}community/{{ community.pk }}/
        {{ community.updated_at|date:"Y-m-d" }}

{% endfor %}
